INSERT INTO posts (id, user_id, board_type, board_key, content, like_count, comment_count, created_at) VALUES
  ('a0000000-0000-0000-0000-000000000001', 'd0000000-0000-0000-0000-000000000015', 'general', NULL, '아기가 분유병을 혼자 잡고 먹어요! 독립심이 자라나는 건가요? ㅋㅋ 뿌듯하면서 쓸쓸 ㅎ', 13, 15, now() - interval '68 days'),
  ('a0000000-0000-0000-0000-000000000002', 'd0000000-0000-0000-0000-000000000098', 'general', NULL, '아기가 분유병을 혼자 잡고 먹어요! 독립심이 자라나는 건가요? ㅋㅋ 뿌듯하면서 쓸쓸 ㅎ', 61, 4, now() + interval '77 days'),
  ('a0000000-0000-0000-0000-000000000003', 'd0000000-0000-0000-0000-000000000078', 'general', NULL, '오늘 아기가 처음으로 "엄마"라고 했어요 🥺 진짜 눈물이 핑 돌더라구요... 6개월 동안 매일 엄마 엄마 하면서 말 걸었는데 드디어...! 이 감동을 어디에 말해야 할지 몰라서 여기 왔어요. 다들 첫 단어가 뭐였어요?', 26, 6, now() + interval '136 days'),
  ('a0000000-0000-0000-0000-000000000004', 'd0000000-0000-0000-0000-000000000077', 'general', NULL, '산후우울증인지 모르겠는데 요즘 이유 없이 울컥해요. 저만 이런 건가요? 🥲', 4, 4, now() + interval '79 days'),
  ('a0000000-0000-0000-0000-000000000005', 'd0000000-0000-0000-0000-000000000008', 'general', NULL, '수면교육 3일차... 15분 울고 잠들었어요. 엄마 마음이 더 아프지만 꾹 참았어요 ㅠㅠ 성공한 맘들 응원 부탁드려요.', 39, 3, now() - interval '125 days'),
  ('a0000000-0000-0000-0000-000000000006', 'd0000000-0000-0000-0000-000000000098', 'birth_month', '2025-10', '2025-10생 아기 "맘마" "빠빠" 말해요! 돌 전에 말 시작하니 대화가 되는 느낌? ㅋㅋ', 11, 5, now() + interval '141 days'),
  ('a0000000-0000-0000-0000-000000000007', 'd0000000-0000-0000-0000-000000000068', 'qna', NULL, '분유에서 우유로 전환 시기가 언제인가요? 돌 지나면 바로 바꿔도 되는 건가요? 🥛', 30, 7, now() + interval '177 days'),
  ('a0000000-0000-0000-0000-000000000008', 'd0000000-0000-0000-0000-000000000092', 'general', NULL, '아기가 책 넘기는 소리를 좋아해서 매일 30권은 넘기는 것 같아요. 내용은 안 보고 넘기기만 ㅋㅋ', 45, 21, now() - interval '133 days'),
  ('a0000000-0000-0000-0000-000000000009', 'd0000000-0000-0000-0000-000000000016', 'general', NULL, '아기한테 매일 "사랑해" 하는데 오늘 처음으로 "사아해~" 하고 따라 했어요 ㅠㅠ 세상에서 제일 행복한 사람은 저예요!!!', 7, 11, now() - interval '142 days'),
  ('a0000000-0000-0000-0000-000000000010', 'd0000000-0000-0000-0000-000000000076', 'general', NULL, '남편이 아기 돌보겠다고 해서 혼자 카페 왔어요. 커피 한 잔의 여유가 이렇게 소중한 줄 몰랐네요 ☕ 그런데 10분마다 사진 보내달래요 ㅋㅋ', 7, 21, now() - interval '18 days'),
  ('a0000000-0000-0000-0000-000000000011', 'd0000000-0000-0000-0000-000000000043', 'general', NULL, '첫째 재우고 둘째 먹이고... 투맘의 하루는 정신없지만 둘 다 잠든 밤이 제일 평화로워요 🌟', 18, 9, now() + interval '55 days'),
  ('a0000000-0000-0000-0000-000000000012', 'd0000000-0000-0000-0000-000000000017', 'region', NULL, '청주 아기띠 체험 가능한 매장 아시나요? 직접 메보고 사고 싶어요.', 59, 19, now() + interval '63 days'),
  ('a0000000-0000-0000-0000-000000000013', 'd0000000-0000-0000-0000-000000000025', 'general', NULL, '밤에 아기 재우고 남편이랑 같이 아기 사진 보면서 귀엽다고 난리치는 시간이 좋아요 ㅋㅋ', 45, 14, now() - interval '106 days'),
  ('a0000000-0000-0000-0000-000000000014', 'd0000000-0000-0000-0000-000000000094', 'general', NULL, '아기가 짝짜꿍 배웠어요! 손뼉 치면서 자기가 더 신나하네요 ㅋㅋ 세상 귀여워', 44, 21, now() - interval '104 days'),
  ('a0000000-0000-0000-0000-000000000015', 'd0000000-0000-0000-0000-000000000014', 'general', NULL, '아기 어린이집 첫 등원 했어요. 문 앞에서 울면서 들어갔는데 데리러 갔더니 까르르 웃으면서 놀고 있어요 🥺', 15, 18, now() + interval '109 days'),
  ('a0000000-0000-0000-0000-000000000016', 'd0000000-0000-0000-0000-000000000036', 'birth_month', '2025-09', '2025-09생 아기 이유식 잘 먹나요? 우리 애는 감자 좋아하는데 당근은 뱉어요 ㅋㅋ 편식 시작인가요?', 58, 3, now() + interval '141 days'),
  ('a0000000-0000-0000-0000-000000000017', 'd0000000-0000-0000-0000-000000000084', 'qna', NULL, '아기 낮잠을 거부해요 ㅠ 눈은 졸린데 안 자려고 버텨요. 낮잠 잘 재우는 팁?', 56, 1, now() + interval '61 days'),
  ('a0000000-0000-0000-0000-000000000018', 'd0000000-0000-0000-0000-000000000053', 'birth_month', '2026-02', '2026-02생 맘 여기 모여요~! 우리 아기들 다들 잘 자라고 있죠? 요즘 뭐가 달라졌는지 공유해요! 😊', 16, 13, now() + interval '43 days'),
  ('a0000000-0000-0000-0000-000000000019', 'd0000000-0000-0000-0000-000000000050', 'general', NULL, '아기랑 첫 놀이동산! 회전목마 탔는데 표정이 멍... ㅋㅋ 좋은 건지 무서운 건지 모르겠어요 🎠', 53, 15, now() - interval '179 days'),
  ('a0000000-0000-0000-0000-000000000020', 'd0000000-0000-0000-0000-000000000020', 'general', NULL, '소아과 가서 성장 체크했는데 백분위 75% 나왔어요! 처음에 작게 태어나서 걱정했는데 쑥쑥 크고 있네요 💪', 16, 2, now() + interval '139 days'),
  ('a0000000-0000-0000-0000-000000000021', 'd0000000-0000-0000-0000-000000000096', 'general', NULL, '아기 첫 이빨 났어요!! 아래 앞니 두 개가 동시에! 칫솔질 어떻게 해야 하는지 아시는 맘?', 6, 19, now() + interval '136 days'),
  ('a0000000-0000-0000-0000-000000000022', 'd0000000-0000-0000-0000-000000000008', 'qna', NULL, '수유쿠션 필요한가요? 없이도 되는 건지... 어떤 브랜드가 좋아요?', 8, 6, now() - interval '18 days'),
  ('a0000000-0000-0000-0000-000000000023', 'd0000000-0000-0000-0000-000000000031', 'birth_month', '2025-08', '2025-08생 아기 예방접종 잘 마쳤어요! 열 없이 지나가서 다행 😌', 63, 19, now() - interval '153 days'),
  ('a0000000-0000-0000-0000-000000000024', 'd0000000-0000-0000-0000-000000000011', 'birth_month', '2025-11', '2025-11생 아기 숟가락 혼자 잡아요! 반은 흘리지만 스스로 하려는 모습이 대견해요 💕', 40, 19, now() + interval '67 days'),
  ('a0000000-0000-0000-0000-000000000025', 'd0000000-0000-0000-0000-000000000092', 'general', NULL, '오늘 처음으로 아기가 고개를 돌려서 저를 찾았어요. "엄마 어디?" 하는 표정에 심장 녹았습니다 ❤️', 19, 13, now() - interval '166 days'),
  ('a0000000-0000-0000-0000-000000000026', 'd0000000-0000-0000-0000-000000000059', 'general', NULL, '친정엄마가 미역국 끓여오셨는데 울면서 먹었어요. 출산 후 처음으로 엄마의 마음을 이해했어요 💕', 51, 3, now() - interval '160 days'),
  ('a0000000-0000-0000-0000-000000000027', 'd0000000-0000-0000-0000-000000000010', 'birth_month', '2025-09', '2025-09생 아기 50일 됐어요! 방긋 웃기 시작했는데 세상 예뻐요. 사진 100장은 찍은 듯 ㅋㅋ', 35, 9, now() - interval '90 days'),
  ('a0000000-0000-0000-0000-000000000028', 'd0000000-0000-0000-0000-000000000048', 'general', NULL, '아기 100일 기념으로 가족사진 찍었는데 완성본 보고 눈물 났어요. 우리가 가족이 됐구나... 🥹', 31, 18, now() + interval '157 days'),
  ('a0000000-0000-0000-0000-000000000029', 'd0000000-0000-0000-0000-000000000002', 'region', NULL, '광주 키즈카페 추천! 넓고 깨끗하고 부모 쉴 공간도 있어요. 커피도 맛있고 ㅎㅎ', 38, 10, now() + interval '27 days'),
  ('a0000000-0000-0000-0000-000000000030', 'd0000000-0000-0000-0000-000000000015', 'qna', NULL, '아기 이가 나려고 하는지 침을 엄청 흘려요. 치발기 추천해주세요!', 50, 18, now() - interval '73 days'),
  ('a0000000-0000-0000-0000-000000000031', 'd0000000-0000-0000-0000-000000000027', 'region', NULL, '김해 맘들 어디서 만나세요? 육아 수다 떨 친구가 필요해요 ㅋㅋ', 16, 22, now() + interval '68 days'),
  ('a0000000-0000-0000-0000-000000000032', 'd0000000-0000-0000-0000-000000000033', 'qna', NULL, '아기가 밤에 열이 나요. 몇 도 이상이면 응급실 가야 하나요? 불안해요 😰', 57, 2, now() - interval '109 days'),
  ('a0000000-0000-0000-0000-000000000033', 'd0000000-0000-0000-0000-000000000036', 'general', NULL, '아기 첫 이빨 났어요!! 아래 앞니 두 개가 동시에! 칫솔질 어떻게 해야 하는지 아시는 맘?', 24, 5, now() + interval '68 days'),
  ('a0000000-0000-0000-0000-000000000034', 'd0000000-0000-0000-0000-000000000095', 'birth_month', '2025-09', '2025-09생 맘들 체중 궁금해요! 우리 9.5kg인데 먹는 양에 비해 안 느는 것 같아서요.', 48, 14, now() + interval '29 days'),
  ('a0000000-0000-0000-0000-000000000035', 'd0000000-0000-0000-0000-000000000020', 'birth_month', '2026-02', '2026-02생 아기 첫 걸음마 시작! 불안불안하게 3걸음 걸었어요. 넘어질 때마다 가슴이 철렁!', 56, 12, now() + interval '38 days'),
  ('a0000000-0000-0000-0000-000000000036', 'd0000000-0000-0000-0000-000000000006', 'general', NULL, '입덧 끝나니 세상이 달라 보여요! 3개월 동안 물만 먹었는데 오늘 치킨 먹었어요 🍗', 60, 2, now() + interval '54 days'),
  ('a0000000-0000-0000-0000-000000000037', 'd0000000-0000-0000-0000-000000000086', 'general', NULL, '엄마 몸이 많이 힘든데 아기 웃음 소리 들으면 충전 100% 돼요. 이 감정이 모성인가 봐요 💪', 52, 18, now() + interval '105 days'),
  ('a0000000-0000-0000-0000-000000000038', 'd0000000-0000-0000-0000-000000000031', 'qna', NULL, '아기 낮잠을 거부해요 ㅠ 눈은 졸린데 안 자려고 버텨요. 낮잠 잘 재우는 팁?', 65, 6, now() + interval '7 days'),
  ('a0000000-0000-0000-0000-000000000039', 'd0000000-0000-0000-0000-000000000095', 'qna', NULL, '산후조리원 2주 vs 4주 어떤 게 좋아요? 첫째라 경험이 없어서요.', 53, 14, now() + interval '64 days'),
  ('a0000000-0000-0000-0000-000000000040', 'd0000000-0000-0000-0000-000000000021', 'region', NULL, '수원 맘들 아기 옷 교환 모임 만들면 참여하실 분? 빠르게 크는 아기옷 서로 나누면 좋을 것 같아요!', 9, 13, now() + interval '121 days'),
  ('a0000000-0000-0000-0000-000000000041', 'd0000000-0000-0000-0000-000000000059', 'general', NULL, '임신 준비하면서 제일 힘든 건 기다림인 것 같아요. 매달 기대하고 실망하고... 같은 마음인 맘들에게 응원 보내요 🍀', 55, 8, now() - interval '169 days'),
  ('a0000000-0000-0000-0000-000000000042', 'd0000000-0000-0000-0000-000000000052', 'general', NULL, '첫 아기 수영 다녀왔는데 물에 들어가자마자 울어서 5분만에 나왔어요 ㅎㅎ 다음엔 적응하겠죠?', 58, 3, now() + interval '72 days'),
  ('a0000000-0000-0000-0000-000000000043', 'd0000000-0000-0000-0000-000000000083', 'birth_month', '2025-09', '2025-09생 아기 "맘마" "빠빠" 말해요! 돌 전에 말 시작하니 대화가 되는 느낌? ㅋㅋ', 46, 18, now() - interval '8 days'),
  ('a0000000-0000-0000-0000-000000000044', 'd0000000-0000-0000-0000-000000000023', 'birth_month', '2026-02', '2026-02생 예정맘인데 곧 만나네요! 출산가방 다 쌌는데 혹시 빠진 거 없는지 봐주세요 🥹', 65, 9, now() - interval '153 days'),
  ('a0000000-0000-0000-0000-000000000045', 'd0000000-0000-0000-0000-000000000094', 'region', NULL, '제주 공원에서 소풍 모임 할 건데 참여할 맘? 도시락 각자 싸오고 아기들끼리 놀아요 🧺', 30, 20, now() + interval '30 days'),
  ('a0000000-0000-0000-0000-000000000046', 'd0000000-0000-0000-0000-000000000025', 'general', NULL, '쌍둥이 임신 확인! 😱 기쁘면서도 걱정이... 쌍둥이 맘들 조언 부탁드려요.', 48, 14, now() - interval '138 days'),
  ('a0000000-0000-0000-0000-000000000047', 'd0000000-0000-0000-0000-000000000047', 'birth_month', '2026-01', '2026-01생 아기 숟가락 혼자 잡아요! 반은 흘리지만 스스로 하려는 모습이 대견해요 💕', 63, 22, now() + interval '160 days'),
  ('a0000000-0000-0000-0000-000000000048', 'd0000000-0000-0000-0000-000000000016', 'region', NULL, '용인 베이비 마사지 배울 수 있는 곳 아시나요? 아기 배 마사지 해주면 잠을 잘 잔다고 해서요.', 22, 17, now() - interval '105 days'),
  ('a0000000-0000-0000-0000-000000000049', 'd0000000-0000-0000-0000-000000000090', 'general', NULL, '시어머니가 이유식 만들어오셨는데 정성이 가득... 우리 아기가 할머니 이유식이 더 잘 먹어요 ㅋㅋ 비밀이에요 🤫', 11, 7, now() + interval '98 days'),
  ('a0000000-0000-0000-0000-000000000050', 'd0000000-0000-0000-0000-000000000079', 'birth_month', '2025-12', '2025-12생 아기 돌잡이 뭐 잡았어요? 우리는 마이크 잡았어요! 🎤 미래의 가수인가 ㅋㅋ', 28, 18, now() + interval '78 days')
INSERT INTO posts (id, user_id, board_type, board_key, content, like_count, comment_count, created_at) VALUES
  ('a0000000-0000-0000-0000-000000000051', 'd0000000-0000-0000-0000-000000000056', 'region', NULL, '전주 맘들 아기 옷 교환 모임 만들면 참여하실 분? 빠르게 크는 아기옷 서로 나누면 좋을 것 같아요!', 41, 21, now() - interval '114 days'),
  ('a0000000-0000-0000-0000-000000000052', 'd0000000-0000-0000-0000-000000000066', 'birth_month', '2026-04', '2026-04생 아기 숟가락 혼자 잡아요! 반은 흘리지만 스스로 하려는 모습이 대견해요 💕', 60, 6, now() + interval '73 days'),
  ('a0000000-0000-0000-0000-000000000053', 'd0000000-0000-0000-0000-000000000082', 'birth_month', '2025-11', '2025-11생 아기 첫 걸음마 시작! 불안불안하게 3걸음 걸었어요. 넘어질 때마다 가슴이 철렁!', 8, 8, now() + interval '58 days'),
  ('a0000000-0000-0000-0000-000000000054', 'd0000000-0000-0000-0000-000000000004', 'general', NULL, '처음으로 아기가 "안녕" 하면서 손 흔들었어요! 인사를 배우다니 ㅠㅠ 우리 아기 사회생활 시작?', 65, 16, now() + interval '19 days'),
  ('a0000000-0000-0000-0000-000000000055', 'd0000000-0000-0000-0000-000000000054', 'qna', NULL, '신생아 옷 사이즈 질문이요! 50, 60이 기본이라는데 우리 아기가 좀 큰 편이에요.', 39, 7, now() + interval '99 days'),
  ('a0000000-0000-0000-0000-000000000056', 'd0000000-0000-0000-0000-000000000052', 'general', NULL, '오늘 유모차 타고 동네 한 바퀴 돌았는데 이웃 할머니들이 아기 보고 예쁘다고 해주셔요. 기분 좋은 하루!', 44, 1, now() + interval '28 days'),
  ('a0000000-0000-0000-0000-000000000057', 'd0000000-0000-0000-0000-000000000029', 'general', NULL, '입덧 끝나니 세상이 달라 보여요! 3개월 동안 물만 먹었는데 오늘 치킨 먹었어요 🍗', 64, 17, now() + interval '143 days'),
  ('a0000000-0000-0000-0000-000000000058', 'd0000000-0000-0000-0000-000000000016', 'birth_month', '2026-05', '2026-05생 맘들 아기 몸무게 어때요? 우리 8kg인데 큰 건지 작은 건지 궁금해요.', 54, 15, now() + interval '144 days'),
  ('a0000000-0000-0000-0000-000000000059', 'd0000000-0000-0000-0000-000000000097', 'qna', NULL, '기초체온 측정하는데 계속 36.2~36.4 사이에요. 배란이 잘 되고 있는 건지 모르겠어요 ㅠㅠ', 42, 17, now() + interval '141 days'),
  ('a0000000-0000-0000-0000-000000000060', 'd0000000-0000-0000-0000-000000000021', 'region', NULL, '성남 아기용품 할인 행사 정보 있으면 공유해주세요! 기저귀 세일 어디서 하나요?', 33, 15, now() - interval '64 days'),
  ('a0000000-0000-0000-0000-000000000061', 'd0000000-0000-0000-0000-000000000063', 'birth_month', '2025-11', '2025-11생 아기 "맘마" "빠빠" 말해요! 돌 전에 말 시작하니 대화가 되는 느낌? ㅋㅋ', 20, 15, now() - interval '74 days'),
  ('a0000000-0000-0000-0000-000000000062', 'd0000000-0000-0000-0000-000000000043', 'general', NULL, '아기 첫 돌 찍으러 스튜디오 갔는데 한복 입은 모습이 너무 사랑스러워요. 앨범 나오면 자랑할 거예요!', 37, 3, now() - interval '60 days'),
  ('a0000000-0000-0000-0000-000000000063', 'd0000000-0000-0000-0000-000000000089', 'general', NULL, '첫째 재우고 둘째 먹이고... 투맘의 하루는 정신없지만 둘 다 잠든 밤이 제일 평화로워요 🌟', 16, 3, now() + interval '85 days'),
  ('a0000000-0000-0000-0000-000000000064', 'd0000000-0000-0000-0000-000000000060', 'birth_month', '2026-07', '2026-07생 맘 여기 모여요~! 우리 아기들 다들 잘 자라고 있죠? 요즘 뭐가 달라졌는지 공유해요! 😊', 16, 14, now() - interval '150 days'),
  ('a0000000-0000-0000-0000-000000000065', 'd0000000-0000-0000-0000-000000000098', 'birth_month', '2026-02', '2026-02생 아기 배밀이 중인데 뒤로만 가요 ㅋㅋ 앞으로 가고 싶은데 자꾸 후진... 귀여워요!', 33, 1, now() + interval '77 days'),
  ('a0000000-0000-0000-0000-000000000066', 'd0000000-0000-0000-0000-000000000069', 'region', NULL, '수원 키즈카페 추천! 넓고 깨끗하고 부모 쉴 공간도 있어요. 커피도 맛있고 ㅎㅎ', 37, 20, now() + interval '125 days'),
  ('a0000000-0000-0000-0000-000000000067', 'd0000000-0000-0000-0000-000000000056', 'birth_month', '2026-07', '2026-07생 맘들 분유 뭐 먹이세요? 우리 애가 지금 먹는 분유에 배가 더부룩한 것 같아서 바꿔볼까 해요.', 27, 11, now() + interval '104 days'),
  ('a0000000-0000-0000-0000-000000000068', 'd0000000-0000-0000-0000-000000000060', 'qna', NULL, '임신 16주차인데 태동을 아직 못 느껴요. 초산이라 잘 모르겠어요 😢', 65, 20, now() + interval '101 days'),
  ('a0000000-0000-0000-0000-000000000069', 'd0000000-0000-0000-0000-000000000073', 'region', NULL, '대전 근처 아기랑 갈 만한 곳 있을까요? 유모차 접근성 좋은 곳이면 좋겠어요~', 8, 21, now() + interval '119 days'),
  ('a0000000-0000-0000-0000-000000000070', 'd0000000-0000-0000-0000-000000000034', 'general', NULL, '아기가 "아빠" 먼저 말해서 남편이 감동의 눈물 흘렸어요 ㅋㅋ 저는 좀 서운하지만 ㅎㅎ', 16, 15, now() - interval '98 days'),
  ('a0000000-0000-0000-0000-000000000071', 'd0000000-0000-0000-0000-000000000097', 'qna', NULL, '임신 준비 중인데 엽산 언제부터 먹어야 하나요? 약국에서 그냥 사면 되는 건가요? 🙏', 29, 9, now() + interval '121 days'),
  ('a0000000-0000-0000-0000-000000000072', 'd0000000-0000-0000-0000-000000000096', 'birth_month', '2026-06', '2026-06생 아기 이유식 잘 먹나요? 우리 애는 감자 좋아하는데 당근은 뱉어요 ㅋㅋ 편식 시작인가요?', 63, 12, now() - interval '18 days'),
  ('a0000000-0000-0000-0000-000000000073', 'd0000000-0000-0000-0000-000000000097', 'general', NULL, '엄마 몸이 많이 힘든데 아기 웃음 소리 들으면 충전 100% 돼요. 이 감정이 모성인가 봐요 💪', 18, 7, now() + interval '160 days'),
  ('a0000000-0000-0000-0000-000000000074', 'd0000000-0000-0000-0000-000000000031', 'general', NULL, '밤에 아기 재우고 남편이랑 같이 아기 사진 보면서 귀엽다고 난리치는 시간이 좋아요 ㅋㅋ', 45, 4, now() + interval '56 days'),
  ('a0000000-0000-0000-0000-000000000075', 'd0000000-0000-0000-0000-000000000090', 'general', NULL, '아기 첫 이빨 났어요!! 아래 앞니 두 개가 동시에! 칫솔질 어떻게 해야 하는지 아시는 맘?', 26, 6, now() + interval '30 days'),
  ('a0000000-0000-0000-0000-000000000076', 'd0000000-0000-0000-0000-000000000040', 'general', NULL, '아기가 기저귀 떼기 시작! 변기에 앉혀놓으면 뿌듯한 표정 짓는 게 ㅋㅋ 성공하면 박수 쳐줘요 👏', 4, 10, now() + interval '97 days'),
  ('a0000000-0000-0000-0000-000000000077', 'd0000000-0000-0000-0000-000000000092', 'general', NULL, '오늘 처음으로 아기가 고개를 돌려서 저를 찾았어요. "엄마 어디?" 하는 표정에 심장 녹았습니다 ❤️', 40, 21, now() - interval '179 days'),
  ('a0000000-0000-0000-0000-000000000078', 'd0000000-0000-0000-0000-000000000088', 'birth_month', '2026-04', '2026-04생 아기 배밀이 중인데 뒤로만 가요 ㅋㅋ 앞으로 가고 싶은데 자꾸 후진... 귀여워요!', 10, 19, now() + interval '89 days'),
  ('a0000000-0000-0000-0000-000000000079', 'd0000000-0000-0000-0000-000000000085', 'general', NULL, '아기랑 첫 놀이동산! 회전목마 탔는데 표정이 멍... ㅋㅋ 좋은 건지 무서운 건지 모르겠어요 🎠', 35, 21, now() - interval '108 days'),
  ('a0000000-0000-0000-0000-000000000080', 'd0000000-0000-0000-0000-000000000014', 'birth_month', '2026-07', '2026-07생 아기 첫 걸음마 시작! 불안불안하게 3걸음 걸었어요. 넘어질 때마다 가슴이 철렁!', 26, 21, now() + interval '118 days'),
  ('a0000000-0000-0000-0000-000000000081', 'd0000000-0000-0000-0000-000000000056', 'general', NULL, '어제 밤 아기가 잠꼬대로 "맘마" 했어요 ㅋㅋ 꿈에서도 밥 생각하는 우리 아기...', 36, 21, now() - interval '138 days'),
  ('a0000000-0000-0000-0000-000000000082', 'd0000000-0000-0000-0000-000000000060', 'birth_month', '2025-09', '2025-09생 아기 "맘마" "빠빠" 말해요! 돌 전에 말 시작하니 대화가 되는 느낌? ㅋㅋ', 49, 19, now() - interval '63 days'),
  ('a0000000-0000-0000-0000-000000000083', 'd0000000-0000-0000-0000-000000000058', 'general', NULL, '아기가 짝짜꿍 배웠어요! 손뼉 치면서 자기가 더 신나하네요 ㅋㅋ 세상 귀여워', 32, 19, now() + interval '98 days'),
  ('a0000000-0000-0000-0000-000000000084', 'd0000000-0000-0000-0000-000000000004', 'birth_month', '2025-12', '2025-12생 맘들 아기 몸무게 어때요? 우리 8kg인데 큰 건지 작은 건지 궁금해요.', 23, 6, now() + interval '91 days'),
  ('a0000000-0000-0000-0000-000000000085', 'd0000000-0000-0000-0000-000000000036', 'qna', NULL, '분유에서 우유로 전환 시기가 언제인가요? 돌 지나면 바로 바꿔도 되는 건가요? 🥛', 47, 9, now() + interval '133 days'),
  ('a0000000-0000-0000-0000-000000000086', 'd0000000-0000-0000-0000-000000000011', 'general', NULL, '아기가 처음 혼자 앉았어요!! 5초... 그리고 쿵 넘어졌지만 그 5초가 기적 같았어요 ✨', 29, 16, now() + interval '62 days'),
  ('a0000000-0000-0000-0000-000000000087', 'd0000000-0000-0000-0000-000000000083', 'region', NULL, '제주 이사 온 지 얼마 안 돼서 친구가 없어요 ㅠ 비슷한 월령 아기 맘이면 좋겠어요.', 31, 1, now() - interval '57 days'),
  ('a0000000-0000-0000-0000-000000000088', 'd0000000-0000-0000-0000-000000000040', 'region', NULL, '천안 예방접종 잘하는 소아과 아시는 분? 아기가 주사 맞고 안 울었으면 좋겠어요 ㅋㅋ', 26, 16, now() + interval '89 days'),
  ('a0000000-0000-0000-0000-000000000089', 'd0000000-0000-0000-0000-000000000043', 'general', NULL, '임신 중에 남편이 매일 태교동화 읽어주는데 아기가 발로 차서 반응해요 😂 남편이 더 신나서 요즘 동화책 3권씩 읽어요 ㅋㅋ', 32, 9, now() - interval '60 days'),
  ('a0000000-0000-0000-0000-000000000090', 'd0000000-0000-0000-0000-000000000093', 'general', NULL, '아기 어린이집 첫 등원 했어요. 문 앞에서 울면서 들어갔는데 데리러 갔더니 까르르 웃으면서 놀고 있어요 🥺', 10, 18, now() + interval '177 days'),
  ('a0000000-0000-0000-0000-000000000091', 'd0000000-0000-0000-0000-000000000025', 'general', NULL, '아기 발 냄새가 고소해요... 이상한가요? ㅋㅋ 자꾸 맡게 돼요 🦶', 33, 9, now() + interval '135 days'),
  ('a0000000-0000-0000-0000-000000000092', 'd0000000-0000-0000-0000-000000000013', 'region', NULL, '서울 예방접종 잘하는 소아과 아시는 분? 아기가 주사 맞고 안 울었으면 좋겠어요 ㅋㅋ', 21, 8, now() - interval '78 days'),
  ('a0000000-0000-0000-0000-000000000093', 'd0000000-0000-0000-0000-000000000017', 'general', NULL, '아기 목욕 시간이 제일 좋아요. 물 만나면 발차기하고 웃고... 근데 꺼내면 세상 끝난 것처럼 울어요 ㅋㅋ', 65, 2, now() + interval '179 days'),
  ('a0000000-0000-0000-0000-000000000094', 'd0000000-0000-0000-0000-000000000082', 'qna', NULL, '임산부 요가 언제부터 시작하면 되나요? 운동을 안 하니 몸이 너무 뻣뻣해요 ㅠ', 34, 4, now() + interval '147 days'),
  ('a0000000-0000-0000-0000-000000000095', 'd0000000-0000-0000-0000-000000000061', 'birth_month', '2026-03', '2026-03생 아기 첫 이가 나왔어요! 아래 앞니인데 웃을 때 보이는 게 너무 귀여워요 😄', 24, 6, now() + interval '65 days'),
  ('a0000000-0000-0000-0000-000000000096', 'd0000000-0000-0000-0000-000000000009', 'birth_month', '2025-10', '2025-10생 아기 첫 걸음마 시작! 불안불안하게 3걸음 걸었어요. 넘어질 때마다 가슴이 철렁!', 7, 19, now() + interval '14 days'),
  ('a0000000-0000-0000-0000-000000000097', 'd0000000-0000-0000-0000-000000000073', 'qna', NULL, '아기 이가 나려고 하는지 침을 엄청 흘려요. 치발기 추천해주세요!', 8, 8, now() - interval '107 days'),
  ('a0000000-0000-0000-0000-000000000098', 'd0000000-0000-0000-0000-000000000077', 'region', NULL, '고양 공원에서 소풍 모임 할 건데 참여할 맘? 도시락 각자 싸오고 아기들끼리 놀아요 🧺', 17, 17, now() - interval '114 days'),
  ('a0000000-0000-0000-0000-000000000099', 'd0000000-0000-0000-0000-000000000055', 'general', NULL, '아기 돌 지나니 말이 폭발적으로 늘어요! 어제는 "주세요"를 처음 했어요.', 42, 2, now() + interval '26 days'),
  ('a0000000-0000-0000-0000-000000000100', 'd0000000-0000-0000-0000-000000000081', 'general', NULL, '오늘 소아과에서 발달검사 했는데 "잘 크고 있어요"라는 말에 눈물이 핑... 맘들 다 잘하고 있는 거예요 💪', 45, 3, now() - interval '45 days')
INSERT INTO posts (id, user_id, board_type, board_key, content, like_count, comment_count, created_at) VALUES
  ('a0000000-0000-0000-0000-000000000101', 'd0000000-0000-0000-0000-000000000010', 'general', NULL, '육아는 체력이라는 말이 진짜였어요. 밤새 안 자는 아기랑 씨름하다 보면 새벽이에요 ㅠ', 29, 15, now() + interval '121 days'),
  ('a0000000-0000-0000-0000-000000000102', 'd0000000-0000-0000-0000-000000000005', 'general', NULL, '아기 첫 발 디딤 👣 7개월부터 잡고 서더니 드디어 혼자 한 발! 순간 온 가족이 박수 치며 환호했어요 ㅋㅋ', 48, 10, now() + interval '117 days'),
  ('a0000000-0000-0000-0000-000000000103', 'd0000000-0000-0000-0000-000000000088', 'general', NULL, '오늘 유모차 타고 동네 한 바퀴 돌았는데 이웃 할머니들이 아기 보고 예쁘다고 해주셔요. 기분 좋은 하루!', 19, 21, now() + interval '51 days'),
  ('a0000000-0000-0000-0000-000000000104', 'd0000000-0000-0000-0000-000000000015', 'birth_month', '2025-09', '2025-09생 아기 이유식 잘 먹나요? 우리 애는 감자 좋아하는데 당근은 뱉어요 ㅋㅋ 편식 시작인가요?', 44, 5, now() + interval '37 days'),
  ('a0000000-0000-0000-0000-000000000105', 'd0000000-0000-0000-0000-000000000022', 'region', NULL, '인천 주말 나들이 추천 장소 있어요? 아기랑 갈 만한 공원이나 카페요!', 41, 19, now() + interval '113 days'),
  ('a0000000-0000-0000-0000-000000000106', 'd0000000-0000-0000-0000-000000000089', 'general', NULL, '이유식 시간이 전쟁터에요 ㅋㅋ 한 숟갈 먹이는데 30분... 바닥은 전쟁 후 같고 아기 얼굴은 고구마 범벅 😂', 28, 9, now() + interval '127 days'),
  ('a0000000-0000-0000-0000-000000000107', 'd0000000-0000-0000-0000-000000000011', 'birth_month', '2025-12', '2025-12생 맘 여기 모여요~! 우리 아기들 다들 잘 자라고 있죠? 요즘 뭐가 달라졌는지 공유해요! 😊', 59, 14, now() + interval '155 days'),
  ('a0000000-0000-0000-0000-000000000108', 'd0000000-0000-0000-0000-000000000012', 'general', NULL, '이유식 거부하던 아기가 바나나는 먹어요!! 바나나 만세! 🍌', 46, 19, now() + interval '6 days'),
  ('a0000000-0000-0000-0000-000000000109', 'd0000000-0000-0000-0000-000000000074', 'general', NULL, '이유식 시간이 전쟁터에요 ㅋㅋ 한 숟갈 먹이는데 30분... 바닥은 전쟁 후 같고 아기 얼굴은 고구마 범벅 😂', 51, 6, now() + interval '167 days'),
  ('a0000000-0000-0000-0000-000000000110', 'd0000000-0000-0000-0000-000000000036', 'general', NULL, '오늘 아기 데리고 처음으로 도서관 갔어요 📚 조용히 해야 되는데 아기가 책 보고 소리 지르길래 얼른 나왔어요 ㅋㅋ', 40, 14, now() + interval '126 days'),
  ('a0000000-0000-0000-0000-000000000111', 'd0000000-0000-0000-0000-000000000061', 'general', NULL, '모유수유 끊으려니 아기보다 제가 더 슬퍼요 ㅠㅠ 마지막 수유할 때 눈물이 주르륵...', 24, 11, now() + interval '42 days'),
  ('a0000000-0000-0000-0000-000000000112', 'd0000000-0000-0000-0000-000000000053', 'region', NULL, '부산 주말 나들이 추천 장소 있어요? 아기랑 갈 만한 공원이나 카페요!', 21, 22, now() + interval '141 days'),
  ('a0000000-0000-0000-0000-000000000113', 'd0000000-0000-0000-0000-000000000012', 'general', NULL, '아기 피부가 너무 좋아요. 볼이 떡 같아서 자꾸 뽀뽀해요. 아기는 싫다는 표정이지만 못 참겠어요 💋', 23, 4, now() + interval '104 days'),
  ('a0000000-0000-0000-0000-000000000114', 'd0000000-0000-0000-0000-000000000001', 'region', NULL, '김해 이유식 배달 서비스 추천해주세요! 직접 만들기 힘들 때가 있어서요...', 37, 15, now() + interval '49 days'),
  ('a0000000-0000-0000-0000-000000000115', 'd0000000-0000-0000-0000-000000000080', 'region', NULL, '성남 예방접종 잘하는 소아과 아시는 분? 아기가 주사 맞고 안 울었으면 좋겠어요 ㅋㅋ', 43, 15, now() + interval '53 days'),
  ('a0000000-0000-0000-0000-000000000116', 'd0000000-0000-0000-0000-000000000017', 'qna', NULL, '아기 이가 나려고 하는지 침을 엄청 흘려요. 치발기 추천해주세요!', 31, 16, now() - interval '162 days'),
  ('a0000000-0000-0000-0000-000000000117', 'd0000000-0000-0000-0000-000000000031', 'region', NULL, '대구 이사 온 지 얼마 안 돼서 친구가 없어요 ㅠ 비슷한 월령 아기 맘이면 좋겠어요.', 22, 18, now() - interval '105 days'),
  ('a0000000-0000-0000-0000-000000000118', 'd0000000-0000-0000-0000-000000000015', 'birth_month', '2026-07', '2026-07생 맘들 낮잠 몇 번 자요? 우리 애는 아직 3번인데 주변에서 2번으로 줄이래요.', 10, 21, now() + interval '128 days'),
  ('a0000000-0000-0000-0000-000000000119', 'd0000000-0000-0000-0000-000000000066', 'region', NULL, '전주 예방접종 잘하는 소아과 아시는 분? 아기가 주사 맞고 안 울었으면 좋겠어요 ㅋㅋ', 29, 16, now() + interval '63 days'),
  ('a0000000-0000-0000-0000-000000000120', 'd0000000-0000-0000-0000-000000000019', 'general', NULL, '수면교육 3일차... 15분 울고 잠들었어요. 엄마 마음이 더 아프지만 꾹 참았어요 ㅠㅠ 성공한 맘들 응원 부탁드려요.', 61, 20, now() + interval '35 days'),
  ('a0000000-0000-0000-0000-000000000121', 'd0000000-0000-0000-0000-000000000036', 'region', NULL, '성남 쪽 소아과 추천 부탁드려요! 잘 봐주시는 선생님 아시는 분? 야간 진료 되면 더 좋겠어요.', 57, 14, now() - interval '130 days'),
  ('a0000000-0000-0000-0000-000000000122', 'd0000000-0000-0000-0000-000000000037', 'region', NULL, '청주 아기랑 가기 좋은 카페 발견! 키즈존도 넓고 이유식 데워주시고 수유실도 있어요 🍊', 56, 19, now() + interval '169 days'),
  ('a0000000-0000-0000-0000-000000000123', 'd0000000-0000-0000-0000-000000000058', 'birth_month', '2026-02', '2026-02 예정맘인데 태명 뭘로 하셨어요? 우리는 "봄이"로 했어요 🌸', 25, 11, now() + interval '140 days'),
  ('a0000000-0000-0000-0000-000000000124', 'd0000000-0000-0000-0000-000000000042', 'qna', NULL, '임신 중 카페인 얼마까지 괜찮아요? 커피 한 잔도 안 되나요?', 65, 8, now() + interval '60 days'),
  ('a0000000-0000-0000-0000-000000000125', 'd0000000-0000-0000-0000-000000000100', 'birth_month', '2026-02', '2026-02생 아기 숟가락 혼자 잡아요! 반은 흘리지만 스스로 하려는 모습이 대견해요 💕', 23, 16, now() + interval '98 days'),
  ('a0000000-0000-0000-0000-000000000126', 'd0000000-0000-0000-0000-000000000084', 'qna', NULL, '태교 음악 뭐 들으세요? 클래식이 좋다고 하는데 저는 발라드가 더 편해요 🎵', 34, 2, now() - interval '152 days'),
  ('a0000000-0000-0000-0000-000000000127', 'd0000000-0000-0000-0000-000000000013', 'qna', NULL, '임신 준비 중인데 엽산 언제부터 먹어야 하나요? 약국에서 그냥 사면 되는 건가요? 🙏', 31, 4, now() + interval '117 days'),
  ('a0000000-0000-0000-0000-000000000128', 'd0000000-0000-0000-0000-000000000093', 'general', NULL, '아기가 처음 혼자 앉았어요!! 5초... 그리고 쿵 넘어졌지만 그 5초가 기적 같았어요 ✨', 58, 21, now() + interval '20 days'),
  ('a0000000-0000-0000-0000-000000000129', 'd0000000-0000-0000-0000-000000000034', 'general', NULL, '이유식 초기인데 아보카도 반응이 대박! 입 벌리고 기다려요 ㅋㅋ 아보카도가 이렇게 비싼데 아기는 모르겠지...', 47, 13, now() + interval '85 days'),
  ('a0000000-0000-0000-0000-000000000130', 'd0000000-0000-0000-0000-000000000049', 'qna', NULL, '아기 이가 나려고 하는지 침을 엄청 흘려요. 치발기 추천해주세요!', 43, 16, now() + interval '10 days'),
  ('a0000000-0000-0000-0000-000000000131', 'd0000000-0000-0000-0000-000000000009', 'general', NULL, '아기가 혼자 서서 박수까지! 발달이 한 번에 오는 것 같아요. 어제까지 못 했는데 오늘 갑자기!', 46, 10, now() + interval '24 days'),
  ('a0000000-0000-0000-0000-000000000132', 'd0000000-0000-0000-0000-000000000013', 'region', NULL, '고양 쪽 소아과 추천 부탁드려요! 잘 봐주시는 선생님 아시는 분? 야간 진료 되면 더 좋겠어요.', 48, 4, now() + interval '178 days'),
  ('a0000000-0000-0000-0000-000000000133', 'd0000000-0000-0000-0000-000000000006', 'general', NULL, '오늘 아기가 거울 보고 자기 모습에 깜짝 놀랐어요 ㅋㅋ 거울 속 아기한테 손도 뻗고 박치기도 하고...', 6, 10, now() - interval '111 days'),
  ('a0000000-0000-0000-0000-000000000134', 'd0000000-0000-0000-0000-000000000032', 'birth_month', '2025-10', '2025-10생 맘들 뒤집기 시작했나요? 우리 애는 옆으로만 가요 ㅋㅋ 통통해서 그런가...', 39, 22, now() + interval '44 days'),
  ('a0000000-0000-0000-0000-000000000135', 'd0000000-0000-0000-0000-000000000079', 'qna', NULL, '젖병 소독 매번 해야 하나요? 6개월 넘으면 안 해도 된다는 말도 있고...', 42, 22, now() - interval '150 days'),
  ('a0000000-0000-0000-0000-000000000136', 'd0000000-0000-0000-0000-000000000030', 'birth_month', '2026-03', '2026-03생 맘들 낮잠 몇 번 자요? 우리 애는 아직 3번인데 주변에서 2번으로 줄이래요.', 19, 15, now() - interval '3 days'),
  ('a0000000-0000-0000-0000-000000000137', 'd0000000-0000-0000-0000-000000000087', 'birth_month', '2025-12', '2025-12생 맘들 어린이집 보내셨어요? 아직 이르려나... 고민 중이에요.', 7, 15, now() + interval '151 days'),
  ('a0000000-0000-0000-0000-000000000138', 'd0000000-0000-0000-0000-000000000055', 'region', NULL, '청주 산부인과 추천 부탁드려요. 첫 임신이라 병원 선택이 어려워요. 🏥', 32, 10, now() - interval '99 days'),
  ('a0000000-0000-0000-0000-000000000139', 'd0000000-0000-0000-0000-000000000031', 'general', NULL, '육아는 체력이라는 말이 진짜였어요. 밤새 안 자는 아기랑 씨름하다 보면 새벽이에요 ㅠ', 25, 19, now() - interval '180 days'),
  ('a0000000-0000-0000-0000-000000000140', 'd0000000-0000-0000-0000-000000000003', 'qna', NULL, '임신 중 카페인 얼마까지 괜찮아요? 커피 한 잔도 안 되나요?', 45, 13, now() - interval '145 days'),
  ('a0000000-0000-0000-0000-000000000141', 'd0000000-0000-0000-0000-000000000088', 'region', NULL, '고양 이사 온 지 얼마 안 돼서 친구가 없어요 ㅠ 비슷한 월령 아기 맘이면 좋겠어요.', 65, 2, now() + interval '128 days'),
  ('a0000000-0000-0000-0000-000000000142', 'd0000000-0000-0000-0000-000000000078', 'region', NULL, '광주 산부인과 추천 부탁드려요. 첫 임신이라 병원 선택이 어려워요. 🏥', 17, 21, now() - interval '65 days'),
  ('a0000000-0000-0000-0000-000000000143', 'd0000000-0000-0000-0000-000000000081', 'birth_month', '2026-07', '2026-07생 아기 첫 걸음마 시작! 불안불안하게 3걸음 걸었어요. 넘어질 때마다 가슴이 철렁!', 22, 15, now() - interval '94 days'),
  ('a0000000-0000-0000-0000-000000000144', 'd0000000-0000-0000-0000-000000000012', 'qna', NULL, '모유 저장 방법 알려주세요! 냉동하면 얼마나 보관 가능해요? 해동은 어떻게?', 23, 14, now() - interval '34 days'),
  ('a0000000-0000-0000-0000-000000000145', 'd0000000-0000-0000-0000-000000000070', 'qna', NULL, '아기가 밤에 열이 나요. 몇 도 이상이면 응급실 가야 하나요? 불안해요 😰', 26, 17, now() + interval '70 days'),
  ('a0000000-0000-0000-0000-000000000146', 'd0000000-0000-0000-0000-000000000022', 'general', NULL, '아기가 짝짜꿍 배웠어요! 손뼉 치면서 자기가 더 신나하네요 ㅋㅋ 세상 귀여워', 55, 16, now() + interval '76 days'),
  ('a0000000-0000-0000-0000-000000000147', 'd0000000-0000-0000-0000-000000000015', 'birth_month', '2026-06', '2026-06생 아기 손 빨기 시작했는데 정상인가요? 공갈젖꼭지 물려야 하나 고민이에요.', 7, 5, now() + interval '58 days'),
  ('a0000000-0000-0000-0000-000000000148', 'd0000000-0000-0000-0000-000000000087', 'qna', NULL, '임신 준비 중인데 엽산 언제부터 먹어야 하나요? 약국에서 그냥 사면 되는 건가요? 🙏', 64, 18, now() - interval '102 days'),
  ('a0000000-0000-0000-0000-000000000149', 'd0000000-0000-0000-0000-000000000034', 'birth_month', '2025-12', '2025-12 예정인데 여름 출산이라 땀띠 걱정... 여름 신생아 케어 팁 부탁해요!', 32, 12, now() + interval '173 days'),
  ('a0000000-0000-0000-0000-000000000150', 'd0000000-0000-0000-0000-000000000049', 'region', NULL, '청주 쪽 소아과 추천 부탁드려요! 잘 봐주시는 선생님 아시는 분? 야간 진료 되면 더 좋겠어요.', 63, 12, now() - interval '60 days')
