  ('a0000000-0000-0000-0000-000000000151', 'd0000000-0000-0000-0000-000000000080', 'qna', NULL, '아기 이유식 알레르기 검사 꼭 해야 하나요? 새로운 음식 줄 때마다 겁나요.', 38, 11, now() + interval '57 days'),
  ('a0000000-0000-0000-0000-000000000152', 'd0000000-0000-0000-0000-000000000009', 'birth_month', '2025-10', '2025-10생 아기 이유식 잘 먹나요? 우리 애는 감자 좋아하는데 당근은 뱉어요 ㅋㅋ 편식 시작인가요?', 32, 10, now() + interval '30 days'),
