  ('a0000000-0000-0000-0000-000000000155', 'd0000000-0000-0000-0000-000000000013', 'region', NULL, '부산 이유식 배달 서비스 추천해주세요! 직접 만들기 힘들 때가 있어서요...', 42, 14, now() + interval '72 days'),
  ('a0000000-0000-0000-0000-000000000156', 'd0000000-0000-0000-0000-000000000028', 'birth_month', '2026-06', '2026-06생 예정맘인데 곧 만나네요! 출산가방 다 쌌는데 혹시 빠진 거 없는지 봐주세요 🥹', 63, 8, now() + interval '26 days'),
  ('a0000000-0000-0000-0000-000000000157', 'd0000000-0000-0000-0000-000000000070', 'qna', NULL, '분유에서 우유로 전환 시기가 언제인가요? 돌 지나면 바로 바꿔도 되는 건가요? 🥛', 44, 12, now() - interval '71 days'),
  ('a0000000-0000-0000-0000-000000000158', 'd0000000-0000-0000-0000-000000000016', 'qna', NULL, '아기 이유식 알레르기 검사 꼭 해야 하나요? 새로운 음식 줄 때마다 겁나요.', 55, 15, now() - interval '55 days'),
  ('a0000000-0000-0000-0000-000000000159', 'd0000000-0000-0000-0000-000000000082', 'birth_month', '2025-10', '2025-10 예정인데 여름 출산이라 땀띠 걱정... 여름 신생아 케어 팁 부탁해요!', 4, 2, now() + interval '63 days'),
  ('a0000000-0000-0000-0000-000000000160', 'd0000000-0000-0000-0000-000000000027', 'general', NULL, '아기한테 매일 "사랑해" 하는데 오늘 처음으로 "사아해~" 하고 따라 했어요 ㅠㅠ 세상에서 제일 행복한 사람은 저예요!!!', 51, 18, now() - interval '56 days'),
  ('a0000000-0000-0000-0000-000000000161', 'd0000000-0000-0000-0000-000000000043', 'region', NULL, '광주 예방접종 잘하는 소아과 아시는 분? 아기가 주사 맞고 안 울었으면 좋겠어요 ㅋㅋ', 53, 20, now() - interval '38 days'),
  ('a0000000-0000-0000-0000-000000000162', 'd0000000-0000-0000-0000-000000000033', 'region', NULL, '서울 이유식 배달 서비스 추천해주세요! 직접 만들기 힘들 때가 있어서요...', 10, 22, now() + interval '34 days'),
  ('a0000000-0000-0000-0000-000000000163', 'd0000000-0000-0000-0000-000000000031', 'birth_month', '2026-07', '2026-07생 아기 배밀이 중인데 뒤로만 가요 ㅋㅋ 앞으로 가고 싶은데 자꾸 후진... 귀여워요!', 4, 6, now() - interval '33 days'),
  ('a0000000-0000-0000-0000-000000000164', 'd0000000-0000-0000-0000-000000000068', 'general', NULL, '아기 피부가 너무 좋아요. 볼이 떡 같아서 자꾸 뽀뽀해요. 아기는 싫다는 표정이지만 못 참겠어요 💋', 7, 16, now() + interval '93 days'),
  ('a0000000-0000-0000-0000-000000000165', 'd0000000-0000-0000-0000-000000000076', 'general', NULL, '카페에서 아기가 조용하게 앉아있길래 뭐 하나 봤더니 휴지를 다 뜯고 있었어요 ㅋㅋ 창의력이라고 하겠습니다...', 35, 8, now() + interval '12 days'),
  ('a0000000-0000-0000-0000-000000000166', 'd0000000-0000-0000-0000-000000000039', 'birth_month', '2026-02', '2026-02생 아기 배밀이 중인데 뒤로만 가요 ㅋㅋ 앞으로 가고 싶은데 자꾸 후진... 귀여워요!', 64, 1, now() - interval '123 days'),
  ('a0000000-0000-0000-0000-000000000167', 'd0000000-0000-0000-0000-000000000088', 'general', NULL, '아기가 까꿍 놀이에 반응하기 시작했어요! 제가 숨으면 두리번거리다가 찾으면 빵 터져요 ㅋㅋ', 48, 15, now() - interval '21 days'),
  ('a0000000-0000-0000-0000-000000000168', 'd0000000-0000-0000-0000-000000000078', 'general', NULL, '오늘 소아과에서 발달검사 했는데 "잘 크고 있어요"라는 말에 눈물이 핑... 맘들 다 잘하고 있는 거예요 💪', 11, 9, now() + interval '150 days'),
  ('a0000000-0000-0000-0000-000000000169', 'd0000000-0000-0000-0000-000000000092', 'general', NULL, '아기가 혼자 서서 박수까지! 발달이 한 번에 오는 것 같아요. 어제까지 못 했는데 오늘 갑자기!', 41, 17, now() - interval '130 days'),
  ('a0000000-0000-0000-0000-000000000170', 'd0000000-0000-0000-0000-000000000013', 'region', NULL, '울산 아기띠 체험 가능한 매장 아시나요? 직접 메보고 사고 싶어요.', 10, 21, now() + interval '142 days'),
  ('a0000000-0000-0000-0000-000000000171', 'd0000000-0000-0000-0000-000000000058', 'qna', NULL, '워킹맘인데 짧은 시간이라도 질 높은 놀이 방법 있을까요? 죄책감이 커요...', 29, 11, now() + interval '103 days'),
  ('a0000000-0000-0000-0000-000000000172', 'd0000000-0000-0000-0000-000000000094', 'general', NULL, '엄마 몸이 많이 힘든데 아기 웃음 소리 들으면 충전 100% 돼요. 이 감정이 모성인가 봐요 💪', 30, 11, now() + interval '96 days'),
  ('a0000000-0000-0000-0000-000000000173', 'd0000000-0000-0000-0000-000000000088', 'qna', NULL, '워킹맘인데 짧은 시간이라도 질 높은 놀이 방법 있을까요? 죄책감이 커요...', 7, 3, now() + interval '24 days'),
  ('a0000000-0000-0000-0000-000000000174', 'd0000000-0000-0000-0000-000000000013', 'region', NULL, '포항 예방접종 잘하는 소아과 아시는 분? 아기가 주사 맞고 안 울었으면 좋겠어요 ㅋㅋ', 26, 5, now() + interval '151 days'),
  ('a0000000-0000-0000-0000-000000000175', 'd0000000-0000-0000-0000-000000000043', 'region', NULL, '부산 산후조리원 가격 비교 중인데 다들 어디 다니셨어요? 경험담 부탁드려요!', 29, 12, now() + interval '109 days'),
  ('a0000000-0000-0000-0000-000000000176', 'd0000000-0000-0000-0000-000000000077', 'general', NULL, '어제 밤 아기가 잠꼬대로 "맘마" 했어요 ㅋㅋ 꿈에서도 밥 생각하는 우리 아기...', 9, 19, now() + interval '40 days'),
  ('a0000000-0000-0000-0000-000000000177', 'd0000000-0000-0000-0000-000000000029', 'region', NULL, '세종 이사 온 지 얼마 안 돼서 친구가 없어요 ㅠ 비슷한 월령 아기 맘이면 좋겠어요.', 25, 18, now() - interval '72 days'),
  ('a0000000-0000-0000-0000-000000000178', 'd0000000-0000-0000-0000-000000000055', 'region', NULL, '포항 쪽 소아과 추천 부탁드려요! 잘 봐주시는 선생님 아시는 분? 야간 진료 되면 더 좋겠어요.', 65, 20, now() + interval '165 days'),
  ('a0000000-0000-0000-0000-000000000179', 'd0000000-0000-0000-0000-000000000078', 'qna', NULL, '아기 두 돌인데 아직 말을 잘 못해요. 언어 치료 받아야 할까요? 걱정이에요 ㅠ', 56, 9, now() - interval '70 days'),
  ('a0000000-0000-0000-0000-000000000180', 'd0000000-0000-0000-0000-000000000098', 'general', NULL, '출산 후 첫 외식!! 남편이랑 아기 맡기고 둘이서 고기 먹었는데 눈물 날 뻔 ㅠㅠ 이 맛이야!', 24, 12, now() - interval '37 days'),
  ('a0000000-0000-0000-0000-000000000181', 'd0000000-0000-0000-0000-000000000009', 'general', NULL, '남편이 육아휴직 신청했어요! 아기랑 시간 보내고 싶다고. 좋은 아빠 맞죠? 🥹', 43, 1, now() - interval '136 days'),
  ('a0000000-0000-0000-0000-000000000182', 'd0000000-0000-0000-0000-000000000049', 'birth_month', '2026-05', '2026-05생 아기 예방접종 잘 마쳤어요! 열 없이 지나가서 다행 😌', 24, 6, now() - interval '84 days'),
  ('a0000000-0000-0000-0000-000000000183', 'd0000000-0000-0000-0000-000000000011', 'qna', NULL, '수유쿠션 필요한가요? 없이도 되는 건지... 어떤 브랜드가 좋아요?', 12, 6, now() + interval '13 days'),
  ('a0000000-0000-0000-0000-000000000184', 'd0000000-0000-0000-0000-000000000011', 'general', NULL, '육아 중 제일 뿌듯한 순간은 아기가 아플 때 엄마 품을 찾을 때인 것 같아요. 내가 필요한 사람이 있다는 게...', 45, 14, now() + interval '114 days'),
  ('a0000000-0000-0000-0000-000000000185', 'd0000000-0000-0000-0000-000000000035', 'general', NULL, '아기 발 냄새가 고소해요... 이상한가요? ㅋㅋ 자꾸 맡게 돼요 🦶', 35, 4, now() - interval '29 days'),
  ('a0000000-0000-0000-0000-000000000186', 'd0000000-0000-0000-0000-000000000087', 'region', NULL, '수원 베이비 마사지 배울 수 있는 곳 아시나요? 아기 배 마사지 해주면 잠을 잘 잔다고 해서요.', 34, 17, now() + interval '12 days'),
  ('a0000000-0000-0000-0000-000000000187', 'd0000000-0000-0000-0000-000000000077', 'general', NULL, '아기 백일인데 남편이 몰래 케이크 준비했어요 🎂 촛불 보고 아기가 손뼉 치는데... 💕', 16, 10, now() + interval '36 days'),
  ('a0000000-0000-0000-0000-000000000188', 'd0000000-0000-0000-0000-000000000038', 'general', NULL, '아기 목욕 시간이 제일 좋아요. 물 만나면 발차기하고 웃고... 근데 꺼내면 세상 끝난 것처럼 울어요 ㅋㅋ', 3, 16, now() + interval '45 days'),
  ('a0000000-0000-0000-0000-000000000189', 'd0000000-0000-0000-0000-000000000049', 'birth_month', '2026-01', '2026-01생 맘들 뒤집기 시작했나요? 우리 애는 옆으로만 가요 ㅋㅋ 통통해서 그런가...', 17, 17, now() + interval '172 days'),
  ('a0000000-0000-0000-0000-000000000190', 'd0000000-0000-0000-0000-000000000051', 'qna', NULL, '임신 중 카페인 얼마까지 괜찮아요? 커피 한 잔도 안 되나요?', 5, 14, now() - interval '20 days'),
  ('a0000000-0000-0000-0000-000000000191', 'd0000000-0000-0000-0000-000000000041', 'birth_month', '2025-12', '2025-12생 아기 첫 이가 나왔어요! 아래 앞니인데 웃을 때 보이는 게 너무 귀여워요 😄', 39, 13, now() + interval '107 days'),
  ('a0000000-0000-0000-0000-000000000192', 'd0000000-0000-0000-0000-000000000052', 'general', NULL, '처음으로 아기가 "안녕" 하면서 손 흔들었어요! 인사를 배우다니 ㅠㅠ 우리 아기 사회생활 시작?', 23, 6, now() + interval '159 days'),
  ('a0000000-0000-0000-0000-000000000193', 'd0000000-0000-0000-0000-000000000089', 'qna', NULL, '워킹맘인데 짧은 시간이라도 질 높은 놀이 방법 있을까요? 죄책감이 커요...', 8, 14, now() + interval '63 days'),
  ('a0000000-0000-0000-0000-000000000194', 'd0000000-0000-0000-0000-000000000076', 'birth_month', '2025-11', '2025-11생 맘들 아기 몸무게 어때요? 우리 8kg인데 큰 건지 작은 건지 궁금해요.', 8, 13, now() + interval '87 days'),
  ('a0000000-0000-0000-0000-000000000195', 'd0000000-0000-0000-0000-000000000100', 'general', NULL, '임신 준비하면서 제일 힘든 건 기다림인 것 같아요. 매달 기대하고 실망하고... 같은 마음인 맘들에게 응원 보내요 🍀', 35, 21, now() - interval '131 days'),
  ('a0000000-0000-0000-0000-000000000196', 'd0000000-0000-0000-0000-000000000100', 'general', NULL, '아기 돌잔치 준비 중인데 잔치 대신 가족여행 가기로 했어요. 돌여행 다녀온 맘들 좋았던 곳 추천해주세요!', 49, 21, now() + interval '61 days'),
  ('a0000000-0000-0000-0000-000000000197', 'd0000000-0000-0000-0000-000000000019', 'general', NULL, '아기 첫 발 디딤 👣 7개월부터 잡고 서더니 드디어 혼자 한 발! 순간 온 가족이 박수 치며 환호했어요 ㅋㅋ', 14, 20, now() - interval '168 days'),
  ('a0000000-0000-0000-0000-000000000198', 'd0000000-0000-0000-0000-000000000023', 'qna', NULL, '아기 아토피 있는 맘들 보습제 뭐 쓰세요? 병원 로션은 너무 비싸요...', 43, 16, now() + interval '145 days'),
  ('a0000000-0000-0000-0000-000000000199', 'd0000000-0000-0000-0000-000000000075', 'birth_month', '2026-01', '2026-01생 맘들 어린이집 보내셨어요? 아직 이르려나... 고민 중이에요.', 62, 19, now() + interval '160 days'),
  ('a0000000-0000-0000-0000-000000000200', 'd0000000-0000-0000-0000-000000000041', 'general', NULL, '아기가 "아빠" 먼저 말해서 남편이 감동의 눈물 흘렸어요 ㅋㅋ 저는 좀 서운하지만 ㅎㅎ', 7, 16, now() + interval '78 days')
INSERT INTO posts (id, user_id, board_type, board_key, content, like_count, comment_count, created_at) VALUES
  ('a0000000-0000-0000-0000-000000000201', 'd0000000-0000-0000-0000-000000000076', 'general', NULL, '남편이 아기 돌보겠다고 해서 혼자 카페 왔어요. 커피 한 잔의 여유가 이렇게 소중한 줄 몰랐네요 ☕ 그런데 10분마다 사진 보내달래요 ㅋㅋ', 35, 3, now() - interval '116 days'),
  ('a0000000-0000-0000-0000-000000000202', 'd0000000-0000-0000-0000-000000000008', 'general', NULL, '아기가 분유병을 혼자 잡고 먹어요! 독립심이 자라나는 건가요? ㅋㅋ 뿌듯하면서 쓸쓸 ㅎ', 21, 3, now() + interval '24 days'),
  ('a0000000-0000-0000-0000-000000000203', 'd0000000-0000-0000-0000-000000000050', 'birth_month', '2026-06', '2026-06생 아기 돌잡이 뭐 잡았어요? 우리는 마이크 잡았어요! 🎤 미래의 가수인가 ㅋㅋ', 38, 2, now() + interval '147 days'),
  ('a0000000-0000-0000-0000-000000000204', 'd0000000-0000-0000-0000-000000000042', 'birth_month', '2025-09', '2025-09생 맘들 아기 몸무게 어때요? 우리 8kg인데 큰 건지 작은 건지 궁금해요.', 35, 5, now() + interval '116 days'),
  ('a0000000-0000-0000-0000-000000000205', 'd0000000-0000-0000-0000-000000000092', 'general', NULL, '이유식 시간이 전쟁터에요 ㅋㅋ 한 숟갈 먹이는데 30분... 바닥은 전쟁 후 같고 아기 얼굴은 고구마 범벅 😂', 44, 6, now() - interval '113 days'),
  ('a0000000-0000-0000-0000-000000000206', 'd0000000-0000-0000-0000-000000000068', 'birth_month', '2026-02', '2026-02생 아기 배밀이 중인데 뒤로만 가요 ㅋㅋ 앞으로 가고 싶은데 자꾸 후진... 귀여워요!', 13, 12, now() - interval '73 days'),
  ('a0000000-0000-0000-0000-000000000207', 'd0000000-0000-0000-0000-000000000100', 'general', NULL, '모유수유 끊으려니 아기보다 제가 더 슬퍼요 ㅠㅠ 마지막 수유할 때 눈물이 주르륵...', 41, 2, now() + interval '166 days'),
  ('a0000000-0000-0000-0000-000000000208', 'd0000000-0000-0000-0000-000000000009', 'general', NULL, '엄마 몸이 많이 힘든데 아기 웃음 소리 들으면 충전 100% 돼요. 이 감정이 모성인가 봐요 💪', 38, 22, now() - interval '65 days'),
  ('a0000000-0000-0000-0000-000000000209', 'd0000000-0000-0000-0000-000000000043', 'general', NULL, '아기가 기저귀 떼기 시작! 변기에 앉혀놓으면 뿌듯한 표정 짓는 게 ㅋㅋ 성공하면 박수 쳐줘요 👏', 45, 5, now() + interval '80 days'),
  ('a0000000-0000-0000-0000-000000000210', 'd0000000-0000-0000-0000-000000000017', 'birth_month', '2026-06', '2026-06생 맘들 아기 몸무게 어때요? 우리 8kg인데 큰 건지 작은 건지 궁금해요.', 63, 3, now() - interval '97 days'),
  ('a0000000-0000-0000-0000-000000000211', 'd0000000-0000-0000-0000-000000000017', 'region', NULL, '천안 아기용품 할인 행사 정보 있으면 공유해주세요! 기저귀 세일 어디서 하나요?', 56, 22, now() + interval '24 days'),
  ('a0000000-0000-0000-0000-000000000212', 'd0000000-0000-0000-0000-000000000047', 'general', NULL, '아기랑 첫 놀이동산! 회전목마 탔는데 표정이 멍... ㅋㅋ 좋은 건지 무서운 건지 모르겠어요 🎠', 22, 6, now() + interval '88 days'),
  ('a0000000-0000-0000-0000-000000000213', 'd0000000-0000-0000-0000-000000000025', 'general', NULL, '아기가 분유병을 혼자 잡고 먹어요! 독립심이 자라나는 건가요? ㅋㅋ 뿌듯하면서 쓸쓸 ㅎ', 11, 5, now() - interval '26 days'),
  ('a0000000-0000-0000-0000-000000000214', 'd0000000-0000-0000-0000-000000000099', 'birth_month', '2026-05', '2026-05생 아기 첫 걸음마 시작! 불안불안하게 3걸음 걸었어요. 넘어질 때마다 가슴이 철렁!', 50, 17, now() - interval '87 days'),
  ('a0000000-0000-0000-0000-000000000215', 'd0000000-0000-0000-0000-000000000077', 'general', NULL, '오늘 아기 데리고 첫 비행기 탔어요 ✈️ 이착륙 때 수유하니까 안 울었어요! 비행기 여행 팁 필요한 맘 있으면 물어보세요~', 13, 6, now() + interval '160 days'),
  ('a0000000-0000-0000-0000-000000000216', 'd0000000-0000-0000-0000-000000000093', 'birth_month', '2026-03', '2026-03생 아기 예방접종 잘 마쳤어요! 열 없이 지나가서 다행 😌', 29, 12, now() + interval '61 days'),
  ('a0000000-0000-0000-0000-000000000217', 'd0000000-0000-0000-0000-000000000037', 'region', NULL, '고양 맘들 어디서 만나세요? 육아 수다 떨 친구가 필요해요 ㅋㅋ', 53, 15, now() - interval '62 days'),
  ('a0000000-0000-0000-0000-000000000218', 'd0000000-0000-0000-0000-000000000025', 'general', NULL, '아기 발 냄새가 고소해요... 이상한가요? ㅋㅋ 자꾸 맡게 돼요 🦶', 63, 19, now() + interval '119 days'),
  ('a0000000-0000-0000-0000-000000000219', 'd0000000-0000-0000-0000-000000000100', 'general', NULL, '출산 후 처음으로 예전 청바지 입었어요! 3개월 걸렸지만 다시 맞다니 ㅠㅠ 조금씩 나를 되찾아가는 기분.', 36, 14, now() + interval '52 days'),
  ('a0000000-0000-0000-0000-000000000220', 'd0000000-0000-0000-0000-000000000033', 'general', NULL, '카페에서 아기가 조용하게 앉아있길래 뭐 하나 봤더니 휴지를 다 뜯고 있었어요 ㅋㅋ 창의력이라고 하겠습니다...', 33, 12, now() + interval '27 days'),
  ('a0000000-0000-0000-0000-000000000221', 'd0000000-0000-0000-0000-000000000016', 'general', NULL, '오늘 아기가 거울 보고 자기 모습에 깜짝 놀랐어요 ㅋㅋ 거울 속 아기한테 손도 뻗고 박치기도 하고...', 51, 6, now() - interval '132 days'),
  ('a0000000-0000-0000-0000-000000000222', 'd0000000-0000-0000-0000-000000000056', 'general', NULL, '이유식 시작했는데 쌀미음 첫 반응이 너무 웃겨요 ㅋㅋ 뭔가 인상을 찡그리면서도 계속 벌리는... 이유식 시작한 맘들 뭐부터 먹였어요?', 61, 8, now() + interval '90 days'),
  ('a0000000-0000-0000-0000-000000000223', 'd0000000-0000-0000-0000-000000000054', 'general', NULL, '아기 머리카락이 자라서 처음으로 묶었는데 핑크 머리끈 하고 너무 예뻐요!! 공주님이야 👸', 35, 12, now() - interval '21 days'),
  ('a0000000-0000-0000-0000-000000000224', 'd0000000-0000-0000-0000-000000000029', 'general', NULL, '모유수유 끊으려니 아기보다 제가 더 슬퍼요 ㅠㅠ 마지막 수유할 때 눈물이 주르륵...', 62, 4, now() + interval '167 days'),
  ('a0000000-0000-0000-0000-000000000225', 'd0000000-0000-0000-0000-000000000019', 'general', NULL, '아기가 처음 혼자 앉았어요!! 5초... 그리고 쿵 넘어졌지만 그 5초가 기적 같았어요 ✨', 21, 16, now() + interval '36 days'),
  ('a0000000-0000-0000-0000-000000000226', 'd0000000-0000-0000-0000-000000000058', 'birth_month', '2025-10', '2025-10생 첫 돌 케이크 어디서 주문했어요? 무설탕 케이크 찾고 있어요~', 60, 3, now() - interval '56 days'),
  ('a0000000-0000-0000-0000-000000000227', 'd0000000-0000-0000-0000-000000000094', 'birth_month', '2025-12', '2025-12생 아기 첫 이가 나왔어요! 아래 앞니인데 웃을 때 보이는 게 너무 귀여워요 😄', 30, 4, now() + interval '61 days'),
  ('a0000000-0000-0000-0000-000000000228', 'd0000000-0000-0000-0000-000000000007', 'general', NULL, '출산 후 1년... 이제 좀 여유가 생겼어요. 처음엔 매일 울었는데 이제는 웃으면서 육아해요. 맘들 다 잘 하고 있어요!', 43, 20, now() + interval '29 days'),
  ('a0000000-0000-0000-0000-000000000229', 'd0000000-0000-0000-0000-000000000077', 'birth_month', '2025-12', '2025-12생 아기 배밀이 중인데 뒤로만 가요 ㅋㅋ 앞으로 가고 싶은데 자꾸 후진... 귀여워요!', 43, 17, now() + interval '37 days'),
  ('a0000000-0000-0000-0000-000000000230', 'd0000000-0000-0000-0000-000000000001', 'birth_month', '2026-06', '2026-06생 맘들 뒤집기 시작했나요? 우리 애는 옆으로만 가요 ㅋㅋ 통통해서 그런가...', 18, 19, now() + interval '171 days'),
  ('a0000000-0000-0000-0000-000000000231', 'd0000000-0000-0000-0000-000000000068', 'qna', NULL, '아기 6개월인데 밤에 아직 3번씩 깨요. 이게 정상인 건가요? 수면교육 해야 할까요?', 7, 17, now() + interval '130 days'),
  ('a0000000-0000-0000-0000-000000000232', 'd0000000-0000-0000-0000-000000000003', 'general', NULL, '아기 백일인데 남편이 몰래 케이크 준비했어요 🎂 촛불 보고 아기가 손뼉 치는데... 💕', 33, 2, now() + interval '96 days'),
  ('a0000000-0000-0000-0000-000000000233', 'd0000000-0000-0000-0000-000000000096', 'general', NULL, '아기 돌잔치 준비 중인데 잔치 대신 가족여행 가기로 했어요. 돌여행 다녀온 맘들 좋았던 곳 추천해주세요!', 53, 3, now() - interval '169 days'),
