  ('a0000000-0000-0000-0000-000000000235', 'd0000000-0000-0000-0000-000000000083', 'general', NULL, '어제 밤 아기가 잠꼬대로 "맘마" 했어요 ㅋㅋ 꿈에서도 밥 생각하는 우리 아기...', 52, 22, now() + interval '179 days'),
  ('a0000000-0000-0000-0000-000000000236', 'd0000000-0000-0000-0000-000000000081', 'general', NULL, '남편이 아기 돌보겠다고 해서 혼자 카페 왔어요. 커피 한 잔의 여유가 이렇게 소중한 줄 몰랐네요 ☕ 그런데 10분마다 사진 보내달래요 ㅋㅋ', 11, 3, now() + interval '118 days'),
  ('a0000000-0000-0000-0000-000000000237', 'd0000000-0000-0000-0000-000000000038', 'general', NULL, '아기랑 같이 낮잠 자는 게 세상에서 제일 행복한 시간이에요. 따뜻한 온기가 느껴져요.', 53, 7, now() + interval '81 days'),
  ('a0000000-0000-0000-0000-000000000238', 'd0000000-0000-0000-0000-000000000066', 'general', NULL, '임신 준비하면서 제일 힘든 건 기다림인 것 같아요. 매달 기대하고 실망하고... 같은 마음인 맘들에게 응원 보내요 🍀', 55, 18, now() + interval '10 days'),
  ('a0000000-0000-0000-0000-000000000239', 'd0000000-0000-0000-0000-000000000037', 'general', NULL, '이유식 거부하던 아기가 바나나는 먹어요!! 바나나 만세! 🍌', 52, 2, now() + interval '85 days'),
  ('a0000000-0000-0000-0000-000000000240', 'd0000000-0000-0000-0000-000000000016', 'region', NULL, '용인 놀이터 좋은 곳 아시는 맘 계세요? 바닥이 폭신하고 그늘 있는 곳 찾고 있어요.', 30, 13, now() + interval '99 days'),
  ('a0000000-0000-0000-0000-000000000241', 'd0000000-0000-0000-0000-000000000064', 'region', NULL, '천안 맘들~ 문화센터 수업 추천해주세요! 6개월 아기랑 다닐 수 있는 곳 찾고 있어요.', 26, 17, now() - interval '22 days'),
  ('a0000000-0000-0000-0000-000000000242', 'd0000000-0000-0000-0000-000000000056', 'birth_month', '2025-09', '2025-09생 맘들 뒤집기 시작했나요? 우리 애는 옆으로만 가요 ㅋㅋ 통통해서 그런가...', 55, 6, now() + interval '83 days'),
  ('a0000000-0000-0000-0000-000000000243', 'd0000000-0000-0000-0000-000000000042', 'region', NULL, '대전 주말 나들이 추천 장소 있어요? 아기랑 갈 만한 공원이나 카페요!', 22, 15, now() + interval '110 days'),
  ('a0000000-0000-0000-0000-000000000244', 'd0000000-0000-0000-0000-000000000045', 'birth_month', '2025-12', '2025-12생 맘들 어린이집 보내셨어요? 아직 이르려나... 고민 중이에요.', 49, 12, now() + interval '112 days'),
  ('a0000000-0000-0000-0000-000000000245', 'd0000000-0000-0000-0000-000000000008', 'general', NULL, '아기 첫 이빨 났어요!! 아래 앞니 두 개가 동시에! 칫솔질 어떻게 해야 하는지 아시는 맘?', 43, 13, now() - interval '174 days'),
  ('a0000000-0000-0000-0000-000000000246', 'd0000000-0000-0000-0000-000000000004', 'general', NULL, '아기 목욕 시간이 제일 좋아요. 물 만나면 발차기하고 웃고... 근데 꺼내면 세상 끝난 것처럼 울어요 ㅋㅋ', 41, 22, now() + interval '9 days'),
  ('a0000000-0000-0000-0000-000000000247', 'd0000000-0000-0000-0000-000000000009', 'general', NULL, '남편이 아기 돌보겠다고 해서 혼자 카페 왔어요. 커피 한 잔의 여유가 이렇게 소중한 줄 몰랐네요 ☕ 그런데 10분마다 사진 보내달래요 ㅋㅋ', 44, 12, now() - interval '146 days'),
  ('a0000000-0000-0000-0000-000000000248', 'd0000000-0000-0000-0000-000000000078', 'general', NULL, '출산 후 처음으로 예전 청바지 입었어요! 3개월 걸렸지만 다시 맞다니 ㅠㅠ 조금씩 나를 되찾아가는 기분.', 31, 12, now() - interval '20 days'),
  ('a0000000-0000-0000-0000-000000000249', 'd0000000-0000-0000-0000-000000000068', 'general', NULL, '이유식 시작했는데 쌀미음 첫 반응이 너무 웃겨요 ㅋㅋ 뭔가 인상을 찡그리면서도 계속 벌리는... 이유식 시작한 맘들 뭐부터 먹였어요?', 23, 21, now() - interval '30 days'),
  ('a0000000-0000-0000-0000-000000000250', 'd0000000-0000-0000-0000-000000000095', 'general', NULL, '오늘 아기 첫 놀이터 데뷔! 모래 처음 만져보고는 표정이 ㅋㅋ', 36, 13, now() + interval '31 days')
INSERT INTO posts (id, user_id, board_type, board_key, content, like_count, comment_count, created_at) VALUES
  ('a0000000-0000-0000-0000-000000000251', 'd0000000-0000-0000-0000-000000000100', 'general', NULL, '아기랑 첫 놀이동산! 회전목마 탔는데 표정이 멍... ㅋㅋ 좋은 건지 무서운 건지 모르겠어요 🎠', 31, 7, now() + interval '74 days'),
  ('a0000000-0000-0000-0000-000000000252', 'd0000000-0000-0000-0000-000000000026', 'general', NULL, '오늘 아기 데리고 처음으로 도서관 갔어요 📚 조용히 해야 되는데 아기가 책 보고 소리 지르길래 얼른 나왔어요 ㅋㅋ', 57, 3, now() + interval '114 days'),
  ('a0000000-0000-0000-0000-000000000253', 'd0000000-0000-0000-0000-000000000088', 'qna', NULL, '아기 6개월인데 밤에 아직 3번씩 깨요. 이게 정상인 건가요? 수면교육 해야 할까요?', 23, 22, now() - interval '17 days'),
  ('a0000000-0000-0000-0000-000000000254', 'd0000000-0000-0000-0000-000000000070', 'general', NULL, '시어머니가 이유식 만들어오셨는데 정성이 가득... 우리 아기가 할머니 이유식이 더 잘 먹어요 ㅋㅋ 비밀이에요 🤫', 22, 6, now() + interval '180 days'),
  ('a0000000-0000-0000-0000-000000000255', 'd0000000-0000-0000-0000-000000000047', 'birth_month', '2026-03', '2026-03생 맘 여기 모여요~! 우리 아기들 다들 잘 자라고 있죠? 요즘 뭐가 달라졌는지 공유해요! 😊', 10, 7, now() + interval '61 days'),
  ('a0000000-0000-0000-0000-000000000256', 'd0000000-0000-0000-0000-000000000047', 'birth_month', '2025-10', '2025-10생 아기 예방접종 잘 마쳤어요! 열 없이 지나가서 다행 😌', 26, 15, now() + interval '142 days'),
  ('a0000000-0000-0000-0000-000000000257', 'd0000000-0000-0000-0000-000000000012', 'general', NULL, '아기 첫 발 디딤 👣 7개월부터 잡고 서더니 드디어 혼자 한 발! 순간 온 가족이 박수 치며 환호했어요 ㅋㅋ', 28, 16, now() + interval '105 days'),
  ('a0000000-0000-0000-0000-000000000258', 'd0000000-0000-0000-0000-000000000017', 'qna', NULL, '분유 온도 몇 도가 적당해요? 온도계 사야 할까요? 너무 뜨거울까봐 무서워요...', 44, 3, now() + interval '175 days'),
  ('a0000000-0000-0000-0000-000000000259', 'd0000000-0000-0000-0000-000000000045', 'general', NULL, '아기 목욕 시간이 제일 좋아요. 물 만나면 발차기하고 웃고... 근데 꺼내면 세상 끝난 것처럼 울어요 ㅋㅋ', 56, 18, now() + interval '47 days'),
  ('a0000000-0000-0000-0000-000000000260', 'd0000000-0000-0000-0000-000000000056', 'birth_month', '2025-10', '2025-10생 맘들 낮잠 몇 번 자요? 우리 애는 아직 3번인데 주변에서 2번으로 줄이래요.', 58, 2, now() + interval '133 days'),
