  ('a0000000-0000-0000-0000-000000000271', 'd0000000-0000-0000-0000-000000000019', 'general', NULL, '입덧 끝나니 세상이 달라 보여요! 3개월 동안 물만 먹었는데 오늘 치킨 먹었어요 🍗', 21, 13, now() + interval '108 days'),
  ('a0000000-0000-0000-0000-000000000272', 'd0000000-0000-0000-0000-000000000021', 'region', NULL, '대전 맘들 어디서 만나세요? 육아 수다 떨 친구가 필요해요 ㅋㅋ', 62, 19, now() + interval '49 days'),
  ('a0000000-0000-0000-0000-000000000273', 'd0000000-0000-0000-0000-000000000066', 'birth_month', '2026-02', '2026-02생 아기 첫 치카! 실리콘 칫솔로 닦아줬는데 재밌어하네요 ㅎㅎ', 59, 10, now() + interval '24 days'),
  ('a0000000-0000-0000-0000-000000000274', 'd0000000-0000-0000-0000-000000000059', 'qna', NULL, '임산부 요가 언제부터 시작하면 되나요? 운동을 안 하니 몸이 너무 뻣뻣해요 ㅠ', 16, 19, now() - interval '13 days'),
