  ('a0000000-0000-0000-0000-000000000277', 'd0000000-0000-0000-0000-000000000052', 'general', NULL, '아기 첫 발 디딤 👣 7개월부터 잡고 서더니 드디어 혼자 한 발! 순간 온 가족이 박수 치며 환호했어요 ㅋㅋ', 38, 7, now() - interval '74 days'),
  ('a0000000-0000-0000-0000-000000000278', 'd0000000-0000-0000-0000-000000000050', 'birth_month', '2026-06', '2026-06생 아기 예방접종 잘 마쳤어요! 열 없이 지나가서 다행 😌', 51, 18, now() - interval '160 days'),
  ('a0000000-0000-0000-0000-000000000279', 'd0000000-0000-0000-0000-000000000016', 'general', NULL, '할머니가 아기한테 동요 불러주시는데 아기가 할머니한테만 배시시 웃어요. 할머니 얼굴에 꽃이 폈어요 🌸', 9, 13, now() - interval '87 days'),
