INSERT INTO market_items (id, user_id, title, description, price, category, baby_age_months, region, photos, status, chat_count, created_at) VALUES
  ('ab000000-0000-0000-0000-000000000001', 'd0000000-0000-0000-0000-000000000002', '봉봉 겨울 패딩 (90사이즈)', '세탁 완료했어요! 깨끗한 상태예요.', 19487, 'clothes', '12+', '고양', '["https://picsum.photos/seed/dodam-market-001-0/400/400","https://picsum.photos/seed/dodam-market-001-1/400/400"]', 'active', 7, now() + interval '42 days'),
  ('ab000000-0000-0000-0000-000000000002', 'd0000000-0000-0000-0000-000000000014', '아벤트 젖병 세트 (미개봉)', '출산 선물로 받았는데 겹쳐서 내놔요. 미개봉이에요!', 27139, 'feeding', '0~6', '김해', '["https://picsum.photos/seed/dodam-market-002-0/400/400","https://picsum.photos/seed/dodam-market-002-1/400/400","https://picsum.photos/seed/dodam-market-002-2/400/400"]', 'active', 3, now() + interval '135 days'),
  ('ab000000-0000-0000-0000-000000000003', 'd0000000-0000-0000-0000-000000000069', '보행기 (사용감 약간 있음)', '세탁 완료했어요! 깨끗한 상태예요.', 53348, 'toys', '0~3', '인천', '["https://picsum.photos/seed/dodam-market-003-0/400/400"]', 'active', 7, now() + interval '5 days'),
  ('ab000000-0000-0000-0000-000000000004', 'd0000000-0000-0000-0000-000000000062', '스토케 트립트랩 하이체어', '1년 사용, 전체적으로 깨끗해요. 직거래 희망!', 172820, 'furniture', '0~6', '창원', '["https://picsum.photos/seed/dodam-market-004-0/400/400","https://picsum.photos/seed/dodam-market-004-1/400/400","https://picsum.photos/seed/dodam-market-004-2/400/400"]', 'active', 7, now() + interval '88 days'),
  ('ab000000-0000-0000-0000-000000000005', 'd0000000-0000-0000-0000-000000000023', '요요 유모차 (경량형)', '상태 매우 좋아요! 거의 새 것이에요. 세 번 정도 사용했어요.', 179871, 'stroller', '3~6', '인천', '["https://picsum.photos/seed/dodam-market-005-0/400/400","https://picsum.photos/seed/dodam-market-005-1/400/400","https://picsum.photos/seed/dodam-market-005-2/400/400"]', 'active', 2, now() - interval '33 days'),
  ('ab000000-0000-0000-0000-000000000006', 'd0000000-0000-0000-0000-000000000027', '아기 내복 세트 (60)', '아기가 커서 안 쓰게 됐어요 ㅠ 잘 쓰실 분 연락주세요!', 10133, 'clothes', '0~3', '천안', '["https://picsum.photos/seed/dodam-market-006-0/400/400"]', 'done', 1, now() + interval '111 days'),
