-- ────────────────────────────────────────────────
-- 완료 메시지
-- ────────────────────────────────────────────────
DO $$
DECLARE
  user_cnt INTEGER;
  post_cnt INTEGER;
  comment_cnt INTEGER;
  review_cnt INTEGER;
  market_cnt INTEGER;
  feed_cnt INTEGER;
  gather_cnt INTEGER;
  like_cnt INTEGER;
  gp_cnt INTEGER;
  gpost_cnt INTEGER;
BEGIN
  SELECT COUNT(*) INTO user_cnt FROM auth.users WHERE email LIKE 'seed%@dodam.app';
  SELECT COUNT(*) INTO post_cnt FROM posts WHERE id::text LIKE 'a0000000%';
  SELECT COUNT(*) INTO comment_cnt FROM comments WHERE id::text LIKE 'c0000000%';
  SELECT COUNT(*) INTO review_cnt FROM reviews WHERE id::text LIKE 'ac000000%';
  SELECT COUNT(*) INTO market_cnt FROM market_items WHERE id::text LIKE 'ab000000%';
  SELECT COUNT(*) INTO feed_cnt FROM town_feed WHERE id::text LIKE 'f0000000%';
  SELECT COUNT(*) INTO gather_cnt FROM town_gatherings WHERE id::text LIKE 'b0000000%';
  SELECT COUNT(*) INTO like_cnt FROM post_likes WHERE id::text LIKE 'e0000000%';
  SELECT COUNT(*) INTO gp_cnt FROM gathering_participants WHERE id::text LIKE 'ad000000%';
  SELECT COUNT(*) INTO gpost_cnt FROM gathering_posts WHERE id::text LIKE 'ae000000%';

  RAISE NOTICE 'Community seed v2 complete!';
  RAISE NOTICE '  Users: %', user_cnt;
  RAISE NOTICE '  Posts: %', post_cnt;
  RAISE NOTICE '  Comments: %', comment_cnt;
  RAISE NOTICE '  Reviews: %', review_cnt;
  RAISE NOTICE '  Market items: %', market_cnt;
  RAISE NOTICE '  Town feed: %', feed_cnt;
  RAISE NOTICE '  Gatherings: %', gather_cnt;
  RAISE NOTICE '  Likes: %', like_cnt;
  RAISE NOTICE '  Gathering participants: %', gp_cnt;
  RAISE NOTICE '  Gathering posts: %', gpost_cnt;
END $$;
